export function BareButton() {
  return (
    <form>
      <button>Submit Form</button>
    </form>
  );
}

export function WithAttrsButton() {
  const handleClick = () => console.log("clicked");
  return <button onClick={handleClick}>Save</button>;
}

export function TypedButton() {
  const handleClick = () => console.log("clicked");
  return <button type="button" onClick={handleClick}>Save</button>;
}

interface AuthCtx {
  user: string | null;
  login: () => void;
  logout: () => void;
}

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const user = "alice";
  const login = () => {};
  const logout = () => {};
  return (
    <AuthContext.Provider value={{ user, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
}

export function ThemeProvider({ children }: { children: React.ReactNode }) {
  const memoizedValue = useMemo(() => ({ mode: "dark" }), []);
  return (
    <ThemeContext.Provider value={memoizedValue}>
      {children}
    </ThemeContext.Provider>
  );
}

export function NameField(props: { name: string }) {
  const [name, setName] = useState(props.name);
  useEffect(() => {
    setName(props.name);
  }, [props.name]);
  return <input value={name} onChange={(e) => setName(e.target.value)} />;
}

export function SeedOnly(props: { initial: string }) {
  const [value, setValue] = useState(props.initial);
  return <input value={value} onChange={(e) => setValue(e.target.value)} />;
}

export function Leaf({ message }: { message: string }) {
  return <span>{message}</span>;
}

export function Middle({ message }: { message: string }) {
  return <Leaf message={message} />;
}

export function Root() {
  return <Middle message="hello" />;
}

interface TreeData {
  label: string;
  children?: TreeData[];
}

export function TreeNode({ data }: { data: TreeData }) {
  return (
    <div>
      <span>{data.label}</span>
      {data.children?.map((c, i) => <TreeNode key={i} data={c} />)}
    </div>
  );
}

export function TreeRoot({ tree }: { tree: TreeData }) {
  return <TreeNode data={tree} />;
}

export function ExternalLink() {
  return (
    <a href="https://example.com" target="_blank">
      External
    </a>
  );
}

export function SafeExternalLink() {
  return (
    <a href="https://example.com" target="_blank" rel="noopener noreferrer">
      External
    </a>
  );
}
